function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function settingsSection(source, title) {
  return source.match(new RegExp(`<SettingsSection title="${escapeRegExp(title)}"[\\s\\S]*?</SettingsSection>`))?.[0] ?? '';
}

function assertSettingsSectionIncludes(source, sourceLabel, title, requiredText) {
  const section = settingsSection(source, title);
  assert.ok(section, `${sourceLabel} must render the ${title} section`);
  for (const text of requiredText) {
    assert.match(section, new RegExp(escapeRegExp(text)), `${title} section must include ${text}`);
  }
}
